Here are the public test cases for feature6_1_mcr_tags_dockerfile_link:
{
  "description": "Generate the registry tags metadata YAML for a repository, controlling how the Dockerfile location is rendered. A template references a repository block and a tag-group block; the engine expands them into a YAML document describing each documented tag group, including the tag list, architecture, OS name, OS display version, and Dockerfile location. When source-control link generation is enabled and a source branch is supplied, the Dockerfile location becomes a permalink of the form '<source repo url>/blob/<branch>/<dockerfile path>'. When link generation is disabled, the Dockerfile location is the plain repository-relative path instead.",
  "cases": [
    {
      "input": {
        "action": "mcr_tags",
        "repo": "repo",
        "generate_github_links": true,
        "source_repo_url": "https://example.com/org/repo",
        "source_branch": "branch",
        "template": "$(McrTagsYmlRepo:repo)\n$(McrTagsYmlTagGroup:tag)",
        "images": [
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os",
                "tags": [
                  "tag"
                ]
              }
            ]
          }
        ]
      },
      "expected_output": "repos:\n- repoName: public/repo\n  customTablePivots: true\n  tagGroups:\n  - tags: [ tag ]\n    architecture: amd64\n    os: linux\n    osVersion: Ubuntu 20.04\n    dockerfile: https://example.com/org/repo/blob/branch/1.0/repo/os/Dockerfile\n"
    },
    {
      "input": {
        "action": "mcr_tags",
        "repo": "repo",
        "generate_github_links": false,
        "template": "$(McrTagsYmlRepo:repo)\n$(McrTagsYmlTagGroup:tag)",
        "images": [
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os",
                "tags": [
                  "tag"
                ]
              }
            ]
          }
        ]
      },
      "expected_output": "repos:\n- repoName: public/repo\n  customTablePivots: true\n  tagGroups:\n  - tags: [ tag ]\n    architecture: amd64\n    os: linux\n    osVersion: Ubuntu 20.04\n    dockerfile: 1.0/repo/os/Dockerfile\n"
    }
  ]
}

Here are the public test cases for feature6_2_mcr_tags_undocumented_platform:
{
  "description": "Generate the registry tags metadata YAML when a repository contains platforms that contribute no documented tags, and shared tags that may or may not be documented. Platforms whose tags are all marked undocumented are omitted from the output entirely; only the platform that owns the requested documented tag appears in its tag group. The tag group lists that platform's documented concrete tags. When the owning image additionally carries a shared tag that is documented for platforms that have documented concrete tags, that shared tag is appended to the same tag group after the concrete tags.",
  "cases": [
    {
      "input": {
        "action": "mcr_tags",
        "repo": "repo",
        "generate_github_links": true,
        "source_repo_url": "https://example.com/org/repo",
        "source_branch": "branch",
        "template": "$(McrTagsYmlRepo:repo)\n$(McrTagsYmlTagGroup:tag1a)\n",
        "images": [
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os",
                "undocumented_tags": [
                  "tag2"
                ]
              }
            ]
          },
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os2",
                "tags": [
                  "tag1a",
                  "tag1b"
                ]
              }
            ]
          }
        ]
      },
      "expected_output": "repos:\n- repoName: public/repo\n  customTablePivots: true\n  tagGroups:\n  - tags: [ tag1a, tag1b ]\n    architecture: amd64\n    os: linux\n    osVersion: Ubuntu 20.04\n    dockerfile: https://example.com/org/repo/blob/branch/1.0/repo/os2/Dockerfile\n"
    },
    {
      "input": {
        "action": "mcr_tags",
        "repo": "repo",
        "generate_github_links": true,
        "source_repo_url": "https://example.com/org/repo",
        "source_branch": "branch",
        "template": "$(McrTagsYmlRepo:repo)\n$(McrTagsYmlTagGroup:tag1a)\n",
        "images": [
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os",
                "undocumented_tags": [
                  "tag2"
                ]
              }
            ]
          },
          {
            "platforms": [
              {
                "dockerfile_dir": "1.0/repo/os2",
                "tags": [
                  "tag1a",
                  "tag1b"
                ]
              }
            ],
            "shared_tags": {
              "shared": {
                "doc_type": "PlatformDocumented"
              }
            }
          }
        ]
      },
      "expected_output": "repos:\n- repoName: public/repo\n  customTablePivots: true\n  tagGroups:\n  - tags: [ tag1a, tag1b, shared ]\n    architecture: amd64\n    os: linux\n    osVersion: Ubuntu 20.04\n    dockerfile: https://example.com/org/repo/blob/branch/1.0/repo/os2/Dockerfile\n"
    }
  ]
}

